options.css:
.rsc-stream-overview { height: 100%; font-family: Inter, Arial, sans-serif; color: inherit; --rsc-border: color-mix(in srgb, currentColor 16%, transparent); --rsc-border-soft: color-mix(in srgb, currentColor 9%, transparent); --rsc-bg: color-mix(in srgb, currentColor 3%, transparent); --rsc-soft: color-mix(in srgb, currentColor 6%, transparent); --rsc-muted: color-mix(in srgb, currentColor 58%, transparent); --rsc-green: #73bf69; --rsc-yellow: #f2cc0c; --rsc-red: #f2495c; --rsc-blue: #5794f2; }
.rsc-overview-list { position: relative; display: grid; gap: 10px; }
.rsc-stream-section { border: 1px solid var(--rsc-border); border-radius: 7px; background: var(--rsc-bg); overflow: visible; box-shadow: inset 0 1px 0 color-mix(in srgb, currentColor 4%, transparent); }
.rsc-stream-section-head { display: grid; grid-template-columns: minmax(220px, 1fr) auto; gap: 12px; align-items: center; padding: 9px 11px; border-bottom: 1px solid var(--rsc-border-soft); background: color-mix(in srgb, currentColor 4%, transparent); }
.rsc-stream-title { min-width: 0; display: grid; gap: 3px; }
.rsc-stream-line, .rsc-group-line { display: flex; align-items: center; gap: 8px; min-width: 0; }
.rsc-health-dot { width: 8px; height: 8px; flex: 0 0 8px; border-radius: 50%; box-shadow: 0 0 0 2px color-mix(in srgb, currentColor 6%, transparent); }
.rsc-health-dot.ok { background: var(--rsc-green); }
.rsc-health-dot.warn { background: var(--rsc-yellow); }
.rsc-health-dot.bad { background: var(--rsc-red); }
.rsc-health-dot.unknown { background: var(--rsc-muted); }
.rsc-stream-name { min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-size: 14px; font-weight: 750; line-height: 1.25; color: inherit; }
.rsc-stream-subtitle { font-size: 10px; color: var(--rsc-muted); line-height: 1.25; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.rsc-stream-stats, .rsc-group-stats { display: flex; flex-wrap: wrap; gap: 5px; justify-content: end; }
.rsc-stat { min-width: 58px; border: 1px solid var(--rsc-border-soft); border-radius: 4px; padding: 4px 6px; background: color-mix(in srgb, currentColor 4%, transparent); }
.rsc-stat-label { display: block; font-size: 9px; line-height: 1.1; color: var(--rsc-muted); text-transform: uppercase; letter-spacing: 0; }
.rsc-stat-value { display: block; margin-top: 2px; font-size: 12px; line-height: 1.1; font-weight: 700; color: inherit; font-variant-numeric: tabular-nums; }
.rsc-stream-groups { display: grid; gap: 8px; padding: 9px; }
.rsc-group-row { border: 1px solid var(--rsc-border-soft); border-radius: 6px; background: color-mix(in srgb, currentColor 2%, transparent); overflow: visible; }
.rsc-group-head { display: grid; grid-template-columns: minmax(190px, 1fr) auto; gap: 9px; align-items: center; padding: 7px 9px; border-bottom: 1px solid var(--rsc-border-soft); }
.rsc-group-title { min-width: 0; display: grid; gap: 2px; }
.rsc-group-name { min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-size: 12px; font-weight: 700; line-height: 1.25; }
.rsc-group-subtitle { font-size: 10px; color: var(--rsc-muted); line-height: 1.25; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.rsc-overview-legend { display: flex; flex-wrap: wrap; gap: 8px; align-items: center; padding: 6px 9px; border-bottom: 1px solid var(--rsc-border-soft); font-size: 11px; line-height: 1.2; color: var(--rsc-muted); }
.rsc-legend-item { display: inline-flex; align-items: center; gap: 5px; white-space: nowrap; }
.rsc-legend-swatch { width: 9px; height: 9px; border-radius: 2px; }
.rsc-legend-swatch.ok { background: var(--rsc-green); }
.rsc-legend-swatch.warn { background: var(--rsc-yellow); }
.rsc-legend-swatch.bad { background: var(--rsc-red); }
.rsc-legend-swatch.unknown { background: var(--rsc-muted); }
.rsc-shard-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(28px, 32px)); gap: 6px; padding: 8px; align-items: start; }
.rsc-shard { position: relative; width: 30px; height: 30px; min-width: 30px; border: 1px solid var(--rsc-border-soft); border-left-width: 3px; border-radius: 4px; background: color-mix(in srgb, currentColor 3%, transparent); color: inherit; display: grid; place-items: center; padding: 0; transition: transform 90ms ease, border-color 90ms ease, background 90ms ease, box-shadow 90ms ease; cursor: default; }
.rsc-shard:hover, .rsc-shard:focus { z-index: 20; transform: translateY(1px) scale(0.992); border-color: color-mix(in srgb, var(--rsc-blue) 64%, var(--rsc-border)); box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--rsc-blue) 18%, transparent), 0 6px 18px color-mix(in srgb, currentColor 14%, transparent); outline: none; }
.rsc-shard.ok { border-left-color: var(--rsc-green); background: color-mix(in srgb, var(--rsc-green) 10%, transparent); }
.rsc-shard.warn { border-left-color: var(--rsc-yellow); background: color-mix(in srgb, var(--rsc-yellow) 11%, transparent); }
.rsc-shard.bad { border-left-color: var(--rsc-red); background: color-mix(in srgb, var(--rsc-red) 10%, transparent); }
.rsc-shard.unknown { border-left-color: var(--rsc-muted); background: var(--rsc-soft); }
.rsc-shard-top { display: grid; place-items: center; width: 100%; height: 100%; min-width: 0; }
.rsc-shard-index { font-size: 11px; font-weight: 750; line-height: 1; font-variant-numeric: tabular-nums; }
.rsc-shard-status { position: absolute; right: 3px; top: 3px; width: 5px; height: 5px; border-radius: 50%; background: var(--rsc-muted); opacity: .9; }
.rsc-shard.ok .rsc-shard-status { background: var(--rsc-green); }
.rsc-shard.warn .rsc-shard-status { background: var(--rsc-yellow); }
.rsc-shard.bad .rsc-shard-status { background: var(--rsc-red); }
.rsc-shard-metric { display: none; }
.rsc-shard-metric span { font-size: 9px; color: var(--rsc-muted); line-height: 1; }
.rsc-shard-metric strong { font-size: 11px; line-height: 1; font-weight: 700; color: inherit; }
.rsc-shard-length { display: none; }
.rsc-shard-detail { display: none; }
.rsc-detail-title { display: flex; justify-content: space-between; gap: 8px; padding-bottom: 6px; margin-bottom: 6px; border-bottom: 1px solid var(--rsc-border-soft); font-weight: 700; }
.rsc-detail-row { display: flex; justify-content: space-between; gap: 8px; margin-top: 4px; }
.rsc-detail-row span { color: var(--rsc-muted); }
.rsc-detail-row strong { color: inherit; text-align: right; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.rsc-hover-detail { position: absolute; z-index: 9999; width: 208px; opacity: 0; pointer-events: none; border: 1px solid var(--rsc-border); border-radius: 6px; background: color-mix(in srgb, Canvas 96%, currentColor 4%); color: CanvasText; box-shadow: 0 10px 28px color-mix(in srgb, currentColor 22%, transparent); padding: 8px; font-size: 11px; line-height: 1.25; font-variant-numeric: tabular-nums; transition: opacity 60ms linear; }
.rsc-hover-detail.visible { opacity: 1; }
.rsc-empty { border: 1px dashed var(--rsc-border); border-radius: 6px; padding: 18px; color: var(--rsc-muted); text-align: center; }
@media (max-width: 900px) { .rsc-stream-section-head, .rsc-group-head { grid-template-columns: 1fr; } .rsc-stream-stats, .rsc-group-stats { grid-template-columns: repeat(2, minmax(0, 1fr)); justify-content: stretch; } .rsc-stat { min-width: 0; } }
@media (max-width: 700px) { .rsc-shard-grid { grid-template-columns: repeat(auto-fill, minmax(42px, 1fr)); } }

options.onInit:
const root = htmlNode.querySelector('[data-role="sharding-overview"]');
if (!root || root.dataset.bound === 'true') {
  return;
}
root.dataset.bound = 'true';

function variable(name) {
