        streamPrefix: shard.streamPrefix,
        consumerGroup: shard.consumerGroup,
        state: 'STABLE',
        shardCount: Number(shard.shardCount || 0),
        activeOwners: new Set(),
        targetOwners: new Set(),
        currentShards: 0,
        targetShards: 0,
        revokingShards: 0,
        totalStreamLength: 0,
        totalPendingCount: 0,
        totalLag: 0,
