    '<div class="rsc-shard-detail">' +
      '<div class="rsc-detail-title"><span>Shard :' + esc(shard.shardIndex) + '</span><strong>' + esc(cls.toUpperCase()) + '</strong></div>' +
      '<div class="rsc-detail-row"><span>Lag</span><strong>' + esc(lagText) + '</strong></div>' +
      '<div class="rsc-detail-row"><span>Length</span><strong>' + esc(lengthText) + '</strong></div>' +
      '<div class="rsc-detail-row"><span>Produced/s</span><strong>' + esc(producedText) + '</strong></div>' +
      '<div class="rsc-detail-row"><span>Consumed/s</span><strong>' + esc(consumedText) + '</strong></div>' +
      '<div class="rsc-detail-row"><span>Owner</span><strong>' + esc(ownerText) + '</strong></div>' +
