      '<div class="rsc-stream-section-head">' +
        '<div class="rsc-stream-title">' +
          '<div class="rsc-stream-line"><span class="rsc-health-dot ' + health + '"></span><span class="rsc-stream-name">' + esc(stream.streamPrefix) + '</span></div>' +
          '<div class="rsc-stream-subtitle">' + stream.groups.length + ' consumer group' + (stream.groups.length === 1 ? '' : 's') + ' grouped under this stream</div>' +
        '</div>' +
        '<div class="rsc-stream-stats">' +
